// 7-Segment Counter: 0-9, increments on button press
// Common Cathode display
// Segments: a=D2, b=D3, c=D4, d=D5, e=D6, f=D7, g=D8
// Button: D12 (INPUT_PULLUP)

const int SEG_A = 2;
const int SEG_B = 3;
const int SEG_C = 4;
const int SEG_D = 5;
const int SEG_E = 6;
const int SEG_F = 7;
const int SEG_G = 8;
const int BTN_PIN = 12;

int count = 0;
int lastBtnState = HIGH;

void showDigit(int n) {
  // a, b, c, d, e, f, g
  if (n == 0) { digitalWrite(SEG_A,1); digitalWrite(SEG_B,1); digitalWrite(SEG_C,1); digitalWrite(SEG_D,1); digitalWrite(SEG_E,1); digitalWrite(SEG_F,1); digitalWrite(SEG_G,0); }
  else if (n == 1) { digitalWrite(SEG_A,0); digitalWrite(SEG_B,1); digitalWrite(SEG_C,1); digitalWrite(SEG_D,0); digitalWrite(SEG_E,0); digitalWrite(SEG_F,0); digitalWrite(SEG_G,0); }
  else if (n == 2) { digitalWrite(SEG_A,1); digitalWrite(SEG_B,1); digitalWrite(SEG_C,0); digitalWrite(SEG_D,1); digitalWrite(SEG_E,1); digitalWrite(SEG_F,0); digitalWrite(SEG_G,1); }
  else if (n == 3) { digitalWrite(SEG_A,1); digitalWrite(SEG_B,1); digitalWrite(SEG_C,1); digitalWrite(SEG_D,1); digitalWrite(SEG_E,0); digitalWrite(SEG_F,0); digitalWrite(SEG_G,1); }
  else if (n == 4) { digitalWrite(SEG_A,0); digitalWrite(SEG_B,1); digitalWrite(SEG_C,1); digitalWrite(SEG_D,0); digitalWrite(SEG_E,0); digitalWrite(SEG_F,1); digitalWrite(SEG_G,1); }
  else if (n == 5) { digitalWrite(SEG_A,1); digitalWrite(SEG_B,0); digitalWrite(SEG_C,1); digitalWrite(SEG_D,1); digitalWrite(SEG_E,0); digitalWrite(SEG_F,1); digitalWrite(SEG_G,1); }
  else if (n == 6) { digitalWrite(SEG_A,1); digitalWrite(SEG_B,0); digitalWrite(SEG_C,1); digitalWrite(SEG_D,1); digitalWrite(SEG_E,1); digitalWrite(SEG_F,1); digitalWrite(SEG_G,1); }
  else if (n == 7) { digitalWrite(SEG_A,1); digitalWrite(SEG_B,1); digitalWrite(SEG_C,1); digitalWrite(SEG_D,0); digitalWrite(SEG_E,0); digitalWrite(SEG_F,0); digitalWrite(SEG_G,0); }
  else if (n == 8) { digitalWrite(SEG_A,1); digitalWrite(SEG_B,1); digitalWrite(SEG_C,1); digitalWrite(SEG_D,1); digitalWrite(SEG_E,1); digitalWrite(SEG_F,1); digitalWrite(SEG_G,1); }
  else if (n == 9) { digitalWrite(SEG_A,1); digitalWrite(SEG_B,1); digitalWrite(SEG_C,1); digitalWrite(SEG_D,1); digitalWrite(SEG_E,0); digitalWrite(SEG_F,1); digitalWrite(SEG_G,1); }
}

void setup() {
  pinMode(SEG_A, OUTPUT);
  pinMode(SEG_B, OUTPUT);
  pinMode(SEG_C, OUTPUT);
  pinMode(SEG_D, OUTPUT);
  pinMode(SEG_E, OUTPUT);
  pinMode(SEG_F, OUTPUT);
  pinMode(SEG_G, OUTPUT);
  pinMode(BTN_PIN, INPUT_PULLUP);
  showDigit(0);
}

void loop() {
  int btnState = digitalRead(BTN_PIN);
  if (btnState == LOW && lastBtnState == HIGH) {
    delay(50); // debounce
    count = count + 1;
    if (count > 9) { count = 0; }
    showDigit(count);
  }
  lastBtnState = btnState;
  delay(10);
}

